package arch.day5;

import java.util.Locale;

/**
 * Day 5 basic: static tables for immutability, pool identity, and comparison rules.
 * // No randomness; println-only teaching aid.
 */
public class Day5Basic {

    static void sep() {
        System.out.println("----------------------------------------");
    }

    public static void main(String[] args) {
        System.out.println("=== Immutability mantra ===");
        System.out.println("String methods return new instances; no in-place char mutation.");
        System.out.println("Reassigning a variable points to a new object; old one may be GC-eligible.");
        sep();
        System.out.println("=== Pool vs new String ===");
        String litA = "token";
        String litB = "token";
        String dyn = new String("token");
        System.out.println("literal == literal -> " + (litA == litB));
        System.out.println("literal == new String -> " + (litA == dyn));
        System.out.println("content equals -> " + litA.equals(dyn));
        sep();
        System.out.println("=== Comparison rule ===");
        System.out.println("Use equals / equalsIgnoreCase for value; == only for deliberate identity.");
        sep();
        System.out.println("=== Locale hint ===");
        System.out.println("Machine keys: toLowerCase(Locale.ROOT); UI text: user Locale + Collator.");
        sep();
        System.out.println("=== StringBuilder hint ===");
        System.out.println("Single-thread loops: StringBuilder; avoid += inside hot loops.");
        sep();
        System.out.println("=== replace vs replaceAll ===");
        System.out.println("replace: literal substring swap; replaceAll: regex engine");
        sep();
        System.out.println("=== indexOf guard ===");
        System.out.println("Check for -1 before substring when parsing optional tokens");
        sep();
        System.out.println("=== Charset reminder ===");
        System.out.println("Always pass StandardCharsets.UTF_8 (or explicit Charset) on getBytes");
        System.out.println("done");
    }
}

