package arch.day5;

import java.nio.charset.StandardCharsets;
import java.util.Locale;

/**
 * Day 5 advanced: three blocks — builder pipeline, regex triage table, charset checklist.
 */
public class Day5Advanced {

    static String normaliseTag(String raw) {
        return raw.trim().toLowerCase(Locale.ROOT);
    }

    static String joinTags(String[] tags) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < tags.length; i++) {
            sb.append(normaliseTag(tags[i]));
            if (i < tags.length - 1) {
                sb.append('|');
            }
        }
        return sb.toString();
    }

    static void printRow(String symptom, String action) {
        String padded = symptom;
        if (padded.length() < 32) {
            padded = padded + " ".repeat(32 - padded.length());
        }
        System.out.println(padded + " | " + action);
    }

    static void block1() {
        System.out.println("=== Block 1: builder pipeline ===");
        String[] tags = {" Java ", "Streams", " OOP "};
        System.out.println("joined=" + joinTags(tags));
        String payload = "hello-utf8";
        byte[] bytes = payload.getBytes(StandardCharsets.UTF_8);
        System.out.println("utf8BytesLen=" + bytes.length);
        System.out.println("hexPreview=manual trace of ASCII bytes not shown");
        System.out.println();
    }

    static void block2() {
        System.out.println("=== Block 2: regex triage ===");
        System.out.println("symptom                          | check");
        System.out.println("---------------------------------|----------------------------");
        printRow("split exploded token count", "escape metacharacters");
        printRow("CPU pegged on one request", "ReDoS / backtracking guard");
        printRow("Case mismatch across regions", "Locale.ROOT vs user Locale");
        printRow("Whitespace surprises", "strip vs trim semantics");
        printRow("Trailing empty split tokens", "limit argument on split");
        printRow("Matches hides compile cost", "hoist Pattern to static final");
        printRow("Null in switch(String)", "guard before switch");
        System.out.println();
    }

    static void block3() {
        System.out.println("=== Block 3: checklist ===");
        System.out.println("1) equals for content 2) explicit Charset on bytes");
        System.out.println("3) Pattern compile once 4) avoid mega string logs");
        System.out.println("5) contentEquals when comparing to builders");
        System.out.println("6) Objects.equals for nullable parameters");
        System.out.println("7) Collator for UI ordering");
        System.out.println("8) Normalizer for auth identifiers");
        System.out.println("review complete");
    }

    public static void main(String[] args) {
        System.out.println("banner: Day5 advanced string operations lab");
        block1();
        block2();
        block3();
        System.out.println("post: run micro-benchmark only with JMH, not println");
        System.out.println("post: document strip vs trim in team style guide");
        System.out.println("post: add CI check for StringBuffer in new code");
    }
}

