package arch.day5;

import java.util.Locale;

/**
 * Day 5 exercise — assignments_phase1.json Day 5 consolidation.
 * Palindrome scan is O(n); builder avoids quadratic concatenation.
 */
public class Day5Exercise {

    static boolean isPalindrome(String s) {
        String cleaned = s.replaceAll("\\s+", "").toLowerCase(Locale.ROOT);
        int left = 0;
        int right = cleaned.length() - 1;
        while (left < right) {
            if (cleaned.charAt(left) != cleaned.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }

    public static void main(String[] args) {
        System.out.println("1) Immutability narration");
        String base = "hello";
        String replaced = base.replace('l', 'L');
        System.out.println("2) original stays hello -> " + base);
        System.out.println("3) replace yields new instance -> " + replaced);
        System.out.println("4) reassignment would only repoint the variable; old object awaits GC if unused");

        String lit1 = "Java";
        String lit2 = "Java";
        String fresh = new String("Java");
        System.out.println("== literals -> " + (lit1 == lit2));
        System.out.println("== literal vs new -> " + (lit1 == fresh));
        System.out.println("equals literal vs new -> " + lit1.equals(fresh));

        String[] tokens = {"alpha", "beta", "gamma", "delta"};
        StringBuilder report = new StringBuilder(tokens.length * 12);
        for (int i = 0; i < tokens.length; i++) {
            report.append("LINE ").append(i + 1).append(':').append(tokens[i]).append((char) 10);
        }
        System.out.print(report.toString());

        // Palindrome two-pointer scan is O(n); avoid += concatenation in loops (would be O(n^2)).
        System.out.println(isPalindrome("racecar"));
        System.out.println(isPalindrome("A man a plan a canal Panama"));
        System.out.println(isPalindrome("hello"));
    }
}

